#include <stdio.h>
int kthElement(int a[], int m, int b[], int n, int k) {
    if (m > n) return kthElement(b, n, a, m, k);
    int low = 0, high = m;
    while (low <= high) {
        int mid = (low + high) / 2;
        int left = mid, right = k - mid;
        int l1 = (mid > 0) ? a[mid - 1] : -1;
        int l2 = (right > 0) ? b[right - 1] : -1;
        int r1 = (mid < m) ? a[mid] : 1000000001;
        int r2 = (right < n) ? b[right] : 1000000001;
        if (l1 <= r2 && l2 <= r1) return (l1 > l2) ? l1 : l2;
        else if (l1 > r2) high = mid - 1;
        else low = mid + 1;
    }
    return -1;
}
int main() {
    int a[] = {1, 3, 5};
    int b[] = {2, 4, 6};
    int k = 4;
    printf("The %d-th element of two sorted arrays is: %d\n", k, kthElement(a, 3, b, 3, k));
    return 0;
}

